INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (523, 164368, 6, 678, '想念你……', '不知道为什么，总是突然想起你，喝酒时想起你，看球时想起你，连睡觉也会想你……我想我疯了，我曾努力控制自己不去想你，但结果却使自己更加想你&#183;&#183;&#183;你锐厉的眼神使我无法忘记，难道我会被你电到？不是的，这一切不是真的&#183;&#183;&#183;我们只见过一次，大家都知道彼此并不合适，做朋友对大家都会好，但真的希望你过的会比我好，真的。如果有一天我们再见面，我想我不会双手插袋，我会把你紧紧拥入怀中。', '不知道为什么，总是突然想起你，喝酒时想起你，看球时想起你，连睡觉也会想你……我想我疯了，我曾努力控制自己不去想你，但结果却使自己更加想你···你锐厉的眼神使我无法忘记，难道我会被你电到？不是的，这一切不是真的···我们只见过一次，大家都知道彼此并不合适，做朋友对大家都会好，但真的希望你过的会比我好，真的。如果有一天我们再见面，我想我不会双手插袋，我会把你紧紧拥入怀中。', '我就是锋疯拉~！最近好衰！！~改天去拜拜……', '2002-06-04 19:24:00', 5, '20020618222325_bbsid_164368_board_6_4a10d68b43.html', '20020618222325');
